# SampleSizeApp
# サンプルサイズ設計ツール。
# ・計算ロジックはすべて pwr / binom / stats に委譲（自前公式は書かない）
# ・UI は bslib::page_navbar、各デザインは Shiny モジュールとして R/modules.R に分離
# ・トップタブ: 連続量 / 二値 / 生存時間 / 1 標本 / 診断精度 / 使い方（最右・既定）

library(shiny)
library(bslib)
library(pwr)
library(binom)

# Shinylive 対応: ggplot2 の依存パッケージを明示的に読み込む
# 実コードからは直接呼ばないが、Shinylive の静的解析が拾えないため
# library() で明示してバンドルに含めさせる。
suppressPackageStartupMessages({
  library(ggplot2)
  library(scales)
  library(munsell)
  library(tibble)
  library(rlang)
  library(cli)
  library(glue)
  library(lifecycle)
  library(vctrs)
  library(pillar)
  library(withr)
  library(magrittr)
  library(fansi)
  library(utf8)
  library(farver)
  library(labeling)
  library(RColorBrewer)
  library(viridisLite)
  library(gtable)
  library(isoband)
  # library(MASS)       # Shinylive の WebAssembly リポジトリに未対応
  # library(Matrix)     # 同上
  # library(mgcv)       # 同上
  # library(nlme)       # 同上
  # library(lattice)    # 同上
})

# 計算層（engine）
source("R/common.R",                    local = TRUE)
source("R/calc_ttest.R",                local = TRUE)
source("R/calc_paired.R",               local = TRUE)
source("R/calc_binary_chisq.R",         local = TRUE)
source("R/calc_binary_fisher.R",        local = TRUE)
source("R/calc_one_mean_precision.R",   local = TRUE)
source("R/calc_one_prop_precision.R",   local = TRUE)
source("R/calc_ttest_ni.R",             local = TRUE)
source("R/calc_paired_ni.R",            local = TRUE)
source("R/calc_binary_ni.R",            local = TRUE)
# --- 新規デザイン (Phase 2 / 3) --------------------------------------
source("R/calc_mcnemar.R",              local = TRUE)
source("R/calc_ancova.R",               local = TRUE)
source("R/calc_logrank.R",              local = TRUE)
source("R/calc_longitudinal.R",         local = TRUE)
source("R/calc_group_sequential.R",     local = TRUE)
source("R/calc_cluster.R",              local = TRUE)
source("R/calc_diagnostic.R",           local = TRUE)
source("R/calc_mann_whitney.R",         local = TRUE)

# テキスト生成・用語解説
source("R/paper_text.R", local = TRUE)
source("R/r_code_gen.R", local = TRUE)
source("R/glossary.R",   local = TRUE)

# UI ヘルパー・モジュール
source("R/ui_helpers.R", local = TRUE)
source("R/modules.R",    local = TRUE)

# ========================================================================
# Theme & CSS
# ========================================================================
app_theme <- bs_theme(
  version   = 5,
  bootswatch = "flatly",
  base_font = font_collection(
    "Hiragino Sans", "Hiragino Kaku Gothic ProN",
    "Yu Gothic", "Meiryo", "sans-serif"
  )
)

extra_css <- tags$style(HTML("
  body { letter-spacing: 0.01em; }
  .help-badge { margin-left: 4px; }
  .card-header { font-weight: 600; }
  .navbar-brand { font-weight: 700; letter-spacing: 0.02em; }
  .nav-item .nav-link { font-weight: 500; }
  pre { background: #f8f9fa; padding: 10px; border-radius: 6px; }
  .value-box-area .bslib-value-box { min-height: 110px; }

  /* ---- 計算モードのセグメントコントロール化 ---- */
  .segmented-radio { margin-bottom: 1rem; }
  .segmented-radio .control-label {
    display: block;
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 0.35rem;
    color: #495057;
  }
  .segmented-radio .shiny-options-group {
    display: flex;
    border: 1px solid #ced4da;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
  }
  .segmented-radio .radio-inline {
    flex: 1 1 0;
    margin: 0 !important;
    padding: 0.55rem 0.75rem;
    text-align: center;
    cursor: pointer;
    font-size: 0.88rem;
    line-height: 1.3;
    transition: background-color 0.15s ease, color 0.15s ease;
    border-left: 1px solid #ced4da;
    user-select: none;
  }
  .segmented-radio .radio-inline:first-of-type { border-left: none; }
  .segmented-radio .radio-inline input[type='radio'] {
    position: absolute;
    opacity: 0;
    pointer-events: none;
  }
  .segmented-radio .radio-inline:has(input[type='radio']:checked) {
    background-color: var(--bs-primary, #2C3E50);
    color: #fff;
    font-weight: 600;
  }
  .segmented-radio .radio-inline:hover:not(:has(input:checked)) {
    background-color: #f1f3f5;
  }
"))

# ========================================================================
# UI
# 大タブ（左から順）:
#   連続量アウトカム / 二値アウトカム / 生存時間解析 / 1 標本（精度ベース）/
#   診断精度 / 使い方（最右・既定タブ）
# 非劣性は独立タブを廃止し、各デザイン画面内の「試験デザイン」ラジオで選択。
# ========================================================================
ui <- page_navbar(
  title = "サンプルサイズ設計ツール",
  theme = app_theme,
  header = extra_css,
  underline = TRUE,
  selected = "使い方",

  nav_panel(
    "連続量アウトカム",
    navset_pill(
      nav_panel("2 群比較（群別入力）",       mod_ttest_m1_ui("m1")),
      nav_panel("2 群比較（差と群別 SD）",    mod_ttest_m2_ui("m2")),
      nav_panel("対応のある t 検定",          mod_paired_ui("pr"))
    )
  ),

  nav_panel(
    "二値アウトカム",
    navset_pill(
      nav_panel("2 群比較（χ² 検定）",            mod_binary_chisq_ui("bin_chi")),
      nav_panel("2 群比較（Fisher の正確検定）", mod_binary_fisher_ui("bin_f")),
      nav_panel("対応のある（McNemar）",          mod_mcnemar_ui("mcn"))
    )
  ),

  nav_panel(
    "生存時間解析",
    navset_pill(
      nav_panel("log-rank 検定",               mod_logrank_ui("lgr"))
    )
  ),

  nav_panel(
    "1 標本（精度ベース）",
    navset_pill(
      nav_panel("平均（精度ベース）",   mod_one_mean_ui("om")),
      nav_panel("割合（精度ベース）",   mod_one_prop_ui("op"))
    )
  ),

  nav_panel(
    "診断精度",
    mod_diagnostic_ui("dgn")
  ),

  nav_panel(
    "使い方",
    mod_guide_ui("guide")
  ),

  nav_spacer(),
  nav_item(
    tags$span(class = "text-muted small",
              "pwr / binom / stats を使用")
  )
)

# ========================================================================
# Server
# ========================================================================
server <- function(input, output, session) {
  mod_ttest_m1_server("m1")
  mod_ttest_m2_server("m2")
  mod_paired_server("pr")
  mod_binary_chisq_server("bin_chi")
  mod_binary_fisher_server("bin_f")
  mod_mcnemar_server("mcn")
  mod_logrank_server("lgr")
  mod_one_mean_server("om")
  mod_one_prop_server("op")
  mod_diagnostic_server("dgn")
  mod_guide_server("guide")
  # 以下のデザインは UI から一時的に非表示（コード・テスト・engine は維持）:
  #   ANCOVA / longitudinal / group_sequential / cluster / Mann-Whitney
}

shinyApp(ui, server)

# ANCOVA（共変量調整）の必要症例数のテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_ancova.R"))

test_that("r = 0 なら通常の t 検定と一致する", {
  ref <- pwr::pwr.t.test(
    d = 0.5, sig.level = 0.05, power = 0.80,
    type = "two.sample", alternative = "two.sided"
  )
  # mean_A = 1, mean_B = 0, sd = 2 → d = 0.5
  res <- calc_n_ancova(mean_A = 1, mean_B = 0, sd_common = 2, r = 0,
                       alpha = 0.05, power = 0.80)
  expect_equal(res$n_per_arm_evaluable, ceiling(ref$n))
})

test_that("|r| が大きいほど必要症例数は少ない（単調性）", {
  res0 <- calc_n_ancova(1, 0, 2, r = 0.0, alpha = 0.05)
  res3 <- calc_n_ancova(1, 0, 2, r = 0.3, alpha = 0.05)
  res7 <- calc_n_ancova(1, 0, 2, r = 0.7, alpha = 0.05)
  expect_gt(res0$n_per_arm_evaluable, res3$n_per_arm_evaluable)
  expect_gt(res3$n_per_arm_evaluable, res7$n_per_arm_evaluable)
})

test_that("Borm 2007 の例（d=0.5, r=0.5）: n_ancova = n_t * (1-r^2)", {
  # r=0.5 → (1 - 0.25) = 0.75 倍で済むはず
  n_t   <- calc_n_ancova(1, 0, 2, r = 0.0, alpha = 0.05)$n_per_arm_evaluable
  n_anc <- calc_n_ancova(1, 0, 2, r = 0.5, alpha = 0.05)$n_per_arm_evaluable
  # 許容: ceiling 丸めで ±2
  expect_lt(abs(n_anc - ceiling(n_t * 0.75)), 3)
})

test_that("|r| >= 1 は拒否される", {
  expect_error(calc_n_ancova(1, 0, 2, r = 1.0, alpha = 0.05))
  expect_error(calc_n_ancova(1, 0, 2, r = -1.1, alpha = 0.05))
})

test_that("mean_A == mean_B では計算が落ちる", {
  expect_error(calc_n_ancova(1, 1, 2, r = 0.5, alpha = 0.05))
})

test_that("脱落率 0.15 で n_randomized が切り上がる", {
  res <- calc_n_ancova(1, 0, 2, r = 0.5,
                       alpha = 0.05, power = 0.80, dropout = 0.15)
  expected_rand <- ceiling(res$n_per_arm_evaluable / 0.85)
  expect_equal(res$n_per_arm_randomized, expected_rand)
})

# 二値・Fisher の正確検定（χ² 近似）のテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_binary_chisq.R"))
source(testthat::test_path("..", "..", "R", "calc_binary_fisher.R"))

test_that("calc_n_binary_fisher: 数値は calc_n_binary_chisq と一致する（近似）", {
  res_f <- calc_n_binary_fisher(0.3, 0.5, alpha = 0.05, power = 0.80)
  res_c <- calc_n_binary_chisq (0.3, 0.5, alpha = 0.05, power = 0.80)
  expect_equal(res_f$n_per_arm_evaluable,  res_c$n_per_arm_evaluable)
  expect_equal(res_f$n_total_evaluable,    res_c$n_total_evaluable)
})

test_that("calc_n_binary_fisher: 警告メッセージがついている", {
  res <- calc_n_binary_fisher(0.3, 0.5, alpha = 0.05, power = 0.80)
  expect_true("warning" %in% names(res))
  expect_true(nchar(res$warning) > 0)
})

test_that("backend_fun と formula_ref が Fisher 用に書き換わっている", {
  res <- calc_n_binary_fisher(0.3, 0.5, alpha = 0.05, power = 0.80)
  expect_match(res$backend_fun, "Fisher")
  expect_match(res$formula_ref, "Fisher")
})

# 群逐次デザイン（OBF / Pocock）の必要症例数のテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_group_sequential.R"))

test_that("K=1 なら固定デザインと一致", {
  ref <- pwr::pwr.t.test(
    d = 0.5, sig.level = 0.05, power = 0.80,
    type = "two.sample", alternative = "two.sided"
  )
  res <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, power = 0.80,
                                 K = 1L, boundary = "OBF")
  expect_equal(res$n_per_arm_evaluable, ceiling(ref$n))
})

test_that("OBF は固定デザインより 1〜4% 多い（K=5）", {
  ref <- pwr::pwr.t.test(
    d = 0.5, sig.level = 0.05, power = 0.80,
    type = "two.sample", alternative = "two.sided"
  )
  res <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, power = 0.80,
                                 K = 5L, boundary = "OBF")
  # inflation 1.028 ± ceiling 切り上げの余裕を見て 1.025 〜 1.05 とする
  ratio <- res$n_per_arm_evaluable / ref$n
  expect_gt(ratio, 1.025); expect_lt(ratio, 1.05)
})

test_that("Pocock は OBF より多い（境界緩い）", {
  n_obf <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, K = 5L,
                                   boundary = "OBF")$n_per_arm_evaluable
  n_poc <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, K = 5L,
                                   boundary = "Pocock")$n_per_arm_evaluable
  expect_gt(n_poc, n_obf)
})

test_that("K が増えるほど n は増える（単調性）", {
  n2 <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, K = 2L,
                                boundary = "Pocock")$n_per_arm_evaluable
  n5 <- calc_n_group_sequential(1, 0, 2, alpha = 0.05, K = 5L,
                                boundary = "Pocock")$n_per_arm_evaluable
  expect_gt(n5, n2)
})

test_that("boundary 未知なら拒否", {
  expect_error(calc_n_group_sequential(1, 0, 2, alpha = 0.05,
                                       K = 3L, boundary = "foo"))
})

test_that("K 範囲外は拒否", {
  expect_error(calc_n_group_sequential(1, 0, 2, alpha = 0.05,
                                       K = 6L, boundary = "OBF"))
})

# Mann-Whitney U 検定（ARE 補正）のテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_mann_whitney.R"))

test_that("ARE テーブル: 正規=3/π, 指数=3, 対数正規=1.5", {
  expect_equal(are_for_distribution("normal"),      3 / pi)
  expect_equal(are_for_distribution("lognormal"),   1.5)
  expect_equal(are_for_distribution("exponential"), 3.0)
})

test_that("normal の必要症例数 = ceiling(n_t / (3/π))", {
  ref_t <- pwr::pwr.t.test(
    d = 0.5, sig.level = 0.05, power = 0.80,
    type = "two.sample", alternative = "two.sided"
  )
  res <- calc_n_mann_whitney(1, 0, 2, distribution = "normal",
                             alpha = 0.05, power = 0.80)
  expect_equal(res$n_per_arm_evaluable, ceiling(ref_t$n / (3 / pi)))
})

test_that("指数分布は正規より n が小さい（ARE が大きい）", {
  n_norm <- calc_n_mann_whitney(1, 0, 2, "normal",
                                alpha = 0.05)$n_per_arm_evaluable
  n_exp  <- calc_n_mann_whitney(1, 0, 2, "exponential",
                                alpha = 0.05)$n_per_arm_evaluable
  expect_gt(n_norm, n_exp)
})

test_that("未知の分布は拒否", {
  expect_error(calc_n_mann_whitney(1, 0, 2, "weird", alpha = 0.05))
})

test_that("脱落率 0.10 で n_randomized が切り上がる", {
  res <- calc_n_mann_whitney(1, 0, 2, "normal",
                             alpha = 0.05, power = 0.80, dropout = 0.10)
  expected_rand <- ceiling(res$n_per_arm_evaluable / 0.9)
  expect_equal(res$n_per_arm_randomized, expected_rand)
})

# 1 標本・割合・精度ベースのテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_one_prop_precision.R"))

test_that("正規近似: n = z^2 * p(1-p) / E^2 を切り上げる", {
  res <- calc_n_one_prop_precision(
    p = 0.3, half_width = 0.05, conf_level = 0.95, method = "normal"
  )
  z <- stats::qnorm(0.975)
  expect_equal(res$n_per_arm_evaluable,
               ceiling(z^2 * 0.3 * 0.7 / 0.05^2))
  expect_equal(res$n_arms, 1L)
  expect_true(is.na(res$achieved_power))
})

test_that("wilson: 見つけた n で binom の半幅 <= E", {
  p <- 0.3; E <- 0.05; cl <- 0.95
  res <- calc_n_one_prop_precision(
    p = p, half_width = E, conf_level = cl, method = "wilson"
  )
  n <- res$n_per_arm_evaluable
  x <- round(p * n)
  ci <- binom::binom.confint(x = x, n = n, conf.level = cl,
                             methods = "wilson")
  expect_true((ci$upper - ci$lower) / 2 <= E + 1e-9)
})

test_that("wilson: n-1 では半幅 > E（最小性の確認）", {
  p <- 0.3; E <- 0.05; cl <- 0.95
  res <- calc_n_one_prop_precision(
    p = p, half_width = E, conf_level = cl, method = "wilson"
  )
  n <- res$n_per_arm_evaluable
  if (n > 2) {
    x <- round(p * (n - 1))
    ci <- binom::binom.confint(x = x, n = n - 1, conf.level = cl,
                               methods = "wilson")
    expect_true((ci$upper - ci$lower) / 2 > E - 1e-9)
  }
})

test_that("exact: 見つけた n で binom の半幅 <= E", {
  p <- 0.3; E <- 0.05; cl <- 0.95
  res <- calc_n_one_prop_precision(
    p = p, half_width = E, conf_level = cl, method = "exact"
  )
  n <- res$n_per_arm_evaluable
  x <- round(p * n)
  ci <- binom::binom.confint(x = x, n = n, conf.level = cl,
                             methods = "exact")
  expect_true((ci$upper - ci$lower) / 2 <= E + 1e-9)
})

test_that("exact は wilson よりやや大きめの n になる（典型例）", {
  p <- 0.3; E <- 0.05; cl <- 0.95
  n_w <- calc_n_one_prop_precision(p, E, cl, "wilson")$n_per_arm_evaluable
  n_e <- calc_n_one_prop_precision(p, E, cl, "exact" )$n_per_arm_evaluable
  expect_gte(n_e, n_w)
})

test_that("脱落率を考慮した n_randomized が切り上がる", {
  res <- calc_n_one_prop_precision(p = 0.3, half_width = 0.05,
                                   method = "wilson", dropout = 0.10)
  expect_equal(res$n_per_arm_randomized,
               ceiling(res$n_per_arm_evaluable / 0.9))
})

# 対応のある t 検定（優越性・両側）のテスト。

source(testthat::test_path("..", "..", "R", "common.R"))
source(testthat::test_path("..", "..", "R", "calc_paired.R"))

test_that("calc_d_paired: |diff| / sd_diff を返す", {
  expect_equal(calc_d_paired(diff_mean = 2, sd_diff = 4), 0.5)
  expect_equal(calc_d_paired(diff_mean = -2, sd_diff = 4), 0.5)
})

test_that("calc_power_paired: pwr.t.test(paired) と一致", {
  ref <- pwr::pwr.t.test(
    n = 30, d = 0.5, sig.level = 0.05,
    type = "paired", alternative = "two.sided"
  )$power
  got <- calc_power_paired(diff_mean = 2, sd_diff = 4, alpha = 0.05, n = 30)
  expect_equal(got, ref, tolerance = 1e-10)
})

test_that("calc_n_paired: pwr を直接叩いた結果と一致する", {
  ref <- ceiling(
    pwr::pwr.t.test(
      d = 0.5, sig.level = 0.05, power = 0.80,
      type = "paired", alternative = "two.sided"
    )$n
  )
  res <- calc_n_paired(diff_mean = 2, sd_diff = 4,
                       alpha = 0.05, power = 0.80)
  expect_equal(res$n_per_arm_evaluable, ref)
  expect_equal(res$n_total_evaluable,   ref)    # n_arms = 1 なので同値
  expect_equal(res$n_arms, 1L)
  expect_equal(res$backend_pkg, "pwr")
})

test_that("calc_n_paired: 脱落率を考慮した n_randomized が切り上がる", {
  ref_eval <- ceiling(
    pwr::pwr.t.test(
      d = 0.5, sig.level = 0.05, power = 0.80,
      type = "paired", alternative = "two.sided"
    )$n
  )
  ref_rand <- ceiling(ref_eval / (1 - 0.20))
  res <- calc_n_paired(diff_mean = 2, sd_diff = 4, alpha = 0.05,
                       power = 0.80, dropout = 0.20)
  expect_equal(res$n_per_arm_evaluable,  ref_eval)
  expect_equal(res$n_per_arm_randomized, ref_rand)
})

# =========================================================================
# 相関係数モード（calc_sd_diff_from_corr / calc_paired_from_corr）
# =========================================================================

test_that("calc_sd_diff_from_corr: r = 0 なら sqrt(sd1^2 + sd2^2)", {
  expect_equal(calc_sd_diff_from_corr(sd_1 = 3, sd_2 = 4, r = 0),
               sqrt(3^2 + 4^2))
  expect_equal(calc_sd_diff_from_corr(sd_1 = 5, sd_2 = 5, r = 0),
               sqrt(50))
})

test_that("calc_sd_diff_from_corr: sd_1=sd_2=4, r=0.5 → 差の SD = 4", {
  # 4 * sqrt(2 * (1 - 0.5)) = 4 * sqrt(1) = 4
  expect_equal(calc_sd_diff_from_corr(sd_1 = 4, sd_2 = 4, r = 0.5), 4)
})

test_that("calc_sd_diff_from_corr: r=1 かつ sd_1=sd_2 → 差の SD = 0 を返す（負にならない）", {
  # 数値誤差で負にならないことの確認
  expect_equal(calc_sd_diff_from_corr(sd_1 = 4, sd_2 = 4, r = 1), 0)
})

test_that("calc_sd_diff_from_corr: 不正な r / SD は落ちる", {
  expect_error(calc_sd_diff_from_corr(sd_1 = 4, sd_2 = 4, r = 1.2))
  expect_error(calc_sd_diff_from_corr(sd_1 = 4, sd_2 = 4, r = -2))
  expect_error(calc_sd_diff_from_corr(sd_1 = 0, sd_2 = 4, r = 0.5))
